#include <stdio.h>
#include <stdlib.h>
#define MAXN 100005
#define MAXM 100005

// Define the structure for the graph
typedef struct {
    int u, v;
} Edge;

// Define the structure for the dynamic programming table
typedef struct {
    double expected_value;
} DP;

// Function to calculate the expected value for each orc
void calculate_expected_value(Edge edges[], int m, int dead_orcs[], int n, DP dp[]) {
    // Initialize the dynamic programming table
    for (int i = 0; i < n; i++) {
        dp[i].expected_value = 0.0;
    }

    // Calculate the expected value for each orc
    for (int i = 0; i < n; i++) {
        // Check if the orc is dead
        if (dead_orcs[i] == 1) {
            dp[i].expected_value = 1.0;
        } else {
            // Calculate the expected value based on the superior orcs
            for (int j = 0; j < m; j++) {
                if (edges[j].v == i + 1) {
                    dp[i].expected_value += dp[edges[j].u - 1].expected_value / (double) n;
                }
            }
        }
    }
}

int main() {
    int t;
    scanf("%d", &t);

    while (t--) {
        int n;
        scanf("%d", &n);

        Edge edges[n - 1];
        for (int i = 0; i < n - 1; i++) {
            scanf("%d %d", &edges[i].u, &edges[i].v);
        }

        int m;
        scanf("%d", &m);
        int dead_orcs[n];
        for (int i = 0; i < n; i++) {
            dead_orcs[i] = 0;
        }
        for (int i = 0; i < m; i++) {
            int orc;
            scanf("%d", &orc);
            dead_orcs[orc - 1] = 1;
        }

        DP dp[n];
        calculate_expected_value(edges, n - 1, dead_orcs, n, dp);

        double expected_value = 0.0;
        for (int i = 0; i < n; i++) {
            expected_value += dp[i].expected_value;
        }
        printf("%.6f\n", expected_value);
    }

    return 0;
}

