        int u, v;

        public Edge(int u, int v) {
            this.u = u;
            this.v = v;
        }
    }

    // Define the structure for the dynamic programming table
    static class DP {
        double expected_value;
    }

    // Function to calculate the expected value for each orc
    public static void calculate_expected_value(Edge[] edges, int[] dead_orcs, DP[] dp) {
        // Initialize the dynamic programming table
        for (int i = 0; i < dp.length; i++) {
            dp[i].expected_value = 0.0;
        }

        // Calculate the expected value for each orc
        for (int i = 0; i < dp.length; i++) {
            // Check if the orc is dead
            if (dead_orcs[i] == 1) {
                dp[i].expected_value = 1.0;
            } else {
                // Calculate the expected value based on the superior orcs
                for (int j = 0; j < edges.length; j++) {
                    if (edges[j].v == i + 1) {
                        dp[i].expected_value += dp[edges[j].u - 1].expected_value / (double) dp.length;
                    }
                }
            }
        }
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int t = scanner.nextInt();

        while (t-- > 0) {
            int n = scanner.nextInt();

            Edge[] edges = new Edge[n - 1];
            for (int i = 0; i < n - 1; i++) {
                int u = scanner.nextInt();
                int v = scanner.nextInt();
                edges[i] = new Edge(u, v);
            }

            int m = scanner.nextInt();
            int[] dead_orcs = new int[n];
            for (int i = 0; i < m; i++) {
                int orc = scanner.nextInt();
                dead_orcs[orc - 1] = 1;
            }

